 1→export const SKETCH_TOOLS = {
 2→  SELECT: 'select',
 3→  RECTANGLE: 'rectangle',
 4→  ELLIPSE: 'ellipse',
 5→  LINE: 'line',
 6→  PEN: 'pen',
 7→};
 8→
 9→export const DEFAULT_SKETCH_ZOOM = 0.15;
10→export const DEFAULT_CANVAS_WIDTH = 297000;
11→export const DEFAULT_CANVAS_HEIGHT = 210000;
12→
13→export const SKETCH_MIN_ZOOM = 0.02;
14→export const SKETCH_MAX_ZOOM = 3.0;
15→export const SKETCH_ZOOM_FACTOR = 1.1;
16→
17→export const SKETCH_GRID_MINOR = 50;   // mm
18→export const SKETCH_GRID_MAJOR = 1000; // mm
19→
20→export const SKETCH_SNAP_DISTANCE_PX = 8;
21→
22→export const SKETCH_OBJECT_CATEGORIES = [
23→  'table', 'chair', 'desk', 'cabinet', 'shelf', 'bed', 'sofa', 'general',
24→];
