  1→export function createSketchSelectHandler({ dispatch, editorDispatch, getLayer, activeLayerId, viewport }) {
  2→  function hitTestShapes(modelPos, layers) {
  3→    // Iterate layers in reverse (top-most first) for correct z-order hit testing
  4→    for (let i = layers.length - 1; i >= 0; i--) {
  5→      const layer = layers[i];
  6→      if (!layer.visible || layer.locked) continue;
  7→
  8→      // Iterate shapes in reverse (top-most first)
  9→      for (let j = layer.shapes.length - 1; j >= 0; j--) {
 10→        const shape = layer.shapes[j];
 11→        if (shapeContainsPoint(shape, modelPos)) {
 12→          return { id: shape.id, type: 'shape', layerId: layer.id };
 13→        }
 14→      }
 15→    }
 16→    return null;
 17→  }
 18→
 19→  function shapeContainsPoint(shape, point) {
 20→    const tolerance = 6 / viewport.zoom;
 21→
 22→    switch (shape.type) {
 23→      case 'rect': {
 24→        return (
 25→          point.x >= shape.x - tolerance &&
 26→          point.x <= shape.x + shape.width + tolerance &&
 27→          point.y >= shape.y - tolerance &&
 28→          point.y <= shape.y + shape.height + tolerance
 29→        );
 30→      }
 31→      case 'ellipse': {
 32→        const cx = shape.x + shape.width / 2;
 33→        const cy = shape.y + shape.height / 2;
 34→        const rx = Math.abs(shape.width) / 2 + tolerance;
 35→        const ry = Math.abs(shape.height) / 2 + tolerance;
 36→        if (rx === 0 || ry === 0) return false;
 37→        const dx = point.x - cx;
 38→        const dy = point.y - cy;
 39→        return (dx * dx) / (rx * rx) + (dy * dy) / (ry * ry) <= 1;
 40→      }
 41→      case 'line': {
 42→        if (shape.points.length < 2) return false;
 43→        const p1 = shape.points[0];
 44→        const p2 = shape.points[1];
 45→        return distToSegment(point, p1, p2) <= tolerance;
 46→      }
 47→      case 'path': {
 48→        if (shape.points.length < 2) return false;
 49→        for (let i = 0; i < shape.points.length - 1; i++) {
 50→          if (distToSegment(point, shape.points[i], shape.points[i + 1]) <= tolerance) {
 51→            return true;
 52→          }
 53→        }
 54→        return false;
 55→      }
 56→      default:
 57→        return false;
 58→    }
 59→  }
 60→
 61→  function distToSegment(p, a, b) {
 62→    const dx = b.x - a.x;
 63→    const dy = b.y - a.y;
 64→    const lenSq = dx * dx + dy * dy;
 65→    if (lenSq === 0) return Math.sqrt((p.x - a.x) ** 2 + (p.y - a.y) ** 2);
 66→    let t = ((p.x - a.x) * dx + (p.y - a.y) * dy) / lenSq;
 67→    t = Math.max(0, Math.min(1, t));
 68→    const projX = a.x + t * dx;
 69→    const projY = a.y + t * dy;
 70→    return Math.sqrt((p.x - projX) ** 2 + (p.y - projY) ** 2);
 71→  }
 72→
 73→  return {
 74→    onMouseDown(modelPos, e, toolState) {
 75→      if (e.button !== 0) return;
 76→
 77→      // Get all layers from the project via the provider
 78→      // We do a simple hit test by checking all visible layers
 79→      const layer = getLayer(activeLayerId);
 80→      const allLayers = layer ? [layer] : [];
 81→
 82→      // For a full implementation, we'd get all layers from project.
 83→      // For the scaffold, just test the active layer shapes.
 84→      if (layer && layer.visible && !layer.locked) {
 85→        for (let i = layer.shapes.length - 1; i >= 0; i--) {
 86→          const shape = layer.shapes[i];
 87→          if (shapeContainsPoint(shape, modelPos)) {
 88→            editorDispatch({ type: 'SELECT_OBJECT', id: shape.id, objectType: 'shape' });
 89→            editorDispatch({
 90→              type: 'UPDATE_TOOL_STATE',
 91→              payload: {
 92→                dragging: false,
 93→                startPos: modelPos,
 94→              },
 95→            });
 96→            return;
 97→          }
 98→        }
 99→      }
100→
101→      // Clicked on empty space - deselect
102→      editorDispatch({ type: 'DESELECT' });
103→    },
104→
105→    onMouseMove(modelPos, e, toolState, selectedId) {
106→      // Drag to move selected shape (stub for future implementation)
107→    },
108→
109→    onMouseUp(modelPos, e, toolState) {
110→      editorDispatch({
111→        type: 'UPDATE_TOOL_STATE',
112→        payload: { dragging: false, startPos: null },
113→      });
114→    },
115→
116→    onKeyDown(e, toolState, selectedId) {
117→      if ((e.key === 'Delete' || e.key === 'Backspace') && selectedId) {
118→        // Find which layer the shape belongs to and delete it
119→        const layer = getLayer(activeLayerId);
120→        if (layer && layer.shapes.some((s) => s.id === selectedId)) {
121→          dispatch({ type: 'SHAPE_DELETE', layerId: layer.id, shapeId: selectedId });
122→          editorDispatch({ type: 'DESELECT' });
123→        }
124→      }
125→    },
126→
127→    getCursor(toolState) {
128→      if (toolState?.dragging) return 'grabbing';
129→      return 'default';
130→    },
131→  };
132→}
