  3→export function createLineHandler({ dispatch, editorDispatch, activeLayerId }) {
  4→  return {
  5→    onMouseDown(modelPos, e, toolState) {
  6→      if (e.button !== 0) return;
  7→
  8→      if (!activeLayerId) {
  9→        editorDispatch({
 10→          type: 'SET_STATUS_MESSAGE',
 11→          message: 'Select a layer before drawing.',
 12→        });
 13→        return;
 14→      }
 15→
 16→      // Start drawing
 17→      editorDispatch({
 18→        type: 'UPDATE_TOOL_STATE',
 19→        payload: {
 20→          drawing: true,
 21→          startPos: { x: modelPos.x, y: modelPos.y },
 22→          currentPos: { x: modelPos.x, y: modelPos.y },
 23→        },
 24→      });
 25→    },
 26→
 27→    onMouseMove(modelPos, e, toolState) {
 28→      if (!toolState.drawing) return;
 29→
 30→      let endPos = { x: modelPos.x, y: modelPos.y };
 31→
 32→      // Shift-key constrains to 45-degree angles
 33→      if (e.shiftKey && toolState.startPos) {
 34→        const dx = modelPos.x - toolState.startPos.x;
 35→        const dy = modelPos.y - toolState.startPos.y;
 36→        const angle = Math.atan2(dy, dx);
 37→        const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 38→        const len = Math.sqrt(dx * dx + dy * dy);
 39→        endPos = {
 40→          x: toolState.startPos.x + Math.cos(snapAngle) * len,
 41→          y: toolState.startPos.y + Math.sin(snapAngle) * len,
 42→        };
 43→      }
 44→
 45→      editorDispatch({
 46→        type: 'UPDATE_TOOL_STATE',
 47→        payload: { currentPos: endPos },
 48→      });
 49→    },
 50→
 51→    onMouseUp(modelPos, e, toolState) {
 52→      if (!toolState.drawing || !toolState.startPos) return;
 53→
 54→      let endPos = { x: modelPos.x, y: modelPos.y };
 55→
 56→      if (e.shiftKey && toolState.startPos) {
 57→        const dx = modelPos.x - toolState.startPos.x;
 58→        const dy = modelPos.y - toolState.startPos.y;
 59→        const angle = Math.atan2(dy, dx);
 60→        const snapAngle = Math.round(angle / (Math.PI / 4)) * (Math.PI / 4);
 61→        const len = Math.sqrt(dx * dx + dy * dy);
 62→        endPos = {
 63→          x: toolState.startPos.x + Math.cos(snapAngle) * len,
 64→          y: toolState.startPos.y + Math.sin(snapAngle) * len,
 65→        };
 66→      }
 67→
 68→      const dx = endPos.x - toolState.startPos.x;
 69→      const dy = endPos.y - toolState.startPos.y;
 70→      const length = Math.sqrt(dx * dx + dy * dy);
 71→
 72→      const minLength = 10; // mm
 73→      if (length > minLength) {
 74→        const shape = createShape('line', {
 75→          layerId: activeLayerId,
 76→          points: [
 77→            { x: toolState.startPos.x, y: toolState.startPos.y },
 78→            { x: endPos.x, y: endPos.y },
 79→          ],
 80→        });
 81→
 82→        dispatch({
 83→          type: 'SHAPE_ADD',
 84→          layerId: activeLayerId,
 85→          shape,
 86→        });
 87→
 88→        editorDispatch({
 89→          type: 'SET_STATUS_MESSAGE',
 90→          message: `Line: ${Math.round(length)} mm`,
 91→        });
 92→      }
 93→
 94→      // Reset tool state
 95→      editorDispatch({
 96→        type: 'UPDATE_TOOL_STATE',
 97→        payload: {
 98→          drawing: false,
 99→          startPos: null,
100→          currentPos: null,
101→        },
102→      });
103→    },
104→
105→    onKeyDown(e) {
106→      if (e.key === 'Escape') {
107→        editorDispatch({
108→          type: 'UPDATE_TOOL_STATE',
109→          payload: {
110→            drawing: false,
111→            startPos: null,
112→            currentPos: null,
113→          },
114→        });
115→      }
116→    },
117→
118→    getCursor(toolState) {
119→      if (toolState?.drawing) return 'crosshair';
120→      return 'crosshair';
