420→function buildTableFixture(group, W, H, D, palette, sel) {
421→  const mat = 'fixture_table';
422→  // Tabletop
423→  addBox(group, mat, W, H * 0.05, D, 0, H * 0.975, 0, palette, sel);
424→  // Front apron
425→  addBox(group, mat, W * 0.90, H * 0.06, D * 0.03, 0, H * 0.92, D * 0.44, palette, sel);
426→  // Back apron
427→  addBox(group, mat, W * 0.90, H * 0.06, D * 0.03, 0, H * 0.92, -D * 0.44, palette, sel);
428→  // Left apron
429→  addBox(group, 'fixtureAccentWood', W * 0.03, H * 0.06, D * 0.80, -W * 0.44, H * 0.92, 0, palette, sel);
430→  // Right apron
431→  addBox(group, 'fixtureAccentWood', W * 0.03, H * 0.06, D * 0.80, W * 0.44, H * 0.92, 0, palette, sel);
432→  // 4 legs
433→  const legR = W * 0.02;
434→  const legH = H * 0.88;
435→  const legY = H * 0.44;
436→  const legPositions = [
437→    { x: -W * 0.43, z: -D * 0.40 },
438→    { x: -W * 0.43, z: D * 0.40 },
439→    { x: W * 0.43, z: -D * 0.40 },
440→    { x: W * 0.43, z: D * 0.40 },
