  // Returns new assembly with partId filtered out
```

`viewProjection.js` -- Pure functions that project a 3D part into 2D SVG coordinates for each orthographic view. This is the critical geometry bridge.

```javascript
export const VIEWS = { TOP: 'top', FRONT: 'front', SIDE: 'side' };

// Top view (looking down -Z): shows X,Y plane
// SVG x = part.position.x, SVG y = part.position.y
export function projectPartToView(part, view)
  // Returns { svgX, svgY, svgWidth, svgHeight } based on part type and view
  // For 'top': svgX=position.x, svgY=position.y, svgWidth=width, svgHeight=depth
  // For 'front': svgX=position.x, svgY=-(position.z + height), svgWidth=width, svgHeight=height
  // For 'side': svgX=position.y, svgY=-(position.z + height), svgWidth=depth, svgHeight=height

export function viewToModelPosition(svgX, svgY, view, existingPosition)
  // Inverse: given 2D SVG coords and a view, compute the 3D position fields for that view
  // 'top': { x: svgX, y: svgY, z: existingPosition.z }
  // 'front': { x: svgX, y: existingPosition.y, z: -svgY }
  // 'side': { x: existingPosition.x, y: svgX, z: -svgY }

export function viewToModelExtents(svgWidth, svgHeight, view, part)
  // Inverse: given 2D extents and a view, compute the 3D dimension fields
  // 'top' for panel: { width: svgWidth, depth: svgHeight }
  // 'front' for panel: { width: svgWidth, thickness: svgHeight } (panel height = thickness in front)
  // etc.

export function getPartExtents(part)
  // Returns { width, depth, height } for any part type (normalizes across types)
  // panel: width, depth, thickness
  // leg: width, depth, height
  // frame: length (along axis), width, height
  // cutout/hole: width, height, depth or diameter, depth

export function getViewLabel(view)
  // Returns 'Top (X-Y)', 'Front (X-Z)', 'Side (Y-Z)'
```

**Modify `defaults.js`** -- Add new tool constants and view constants. Keep existing grid/zoom/snap constants.

```javascript
