**`partPlaceHandler.js`** -- Generic handler factory for placing panel, leg, frame parts. Takes `partType` as parameter.

```javascript
import { createPanel, createLeg, createFrame, createCutout } from '../../domain/partModels';
import { viewToModelPosition, viewToModelExtents } from '../../domain/viewProjection';
import { PART_DEFAULTS } from '../../domain/partDefaults';

const PART_FACTORIES = { panel: createPanel, leg: createLeg, frame: createFrame, cutout: createCutout };

export function createPartPlaceHandler({ dispatch, editorDispatch, activeView, activeAssemblyId, partType }) {
  const factory = PART_FACTORIES[partType];
  const defaults = PART_DEFAULTS[partType];

  return {
    onMouseDown(modelPos, e, toolState) {
      if (e.button !== 0) return;
      editorDispatch({
        type: 'UPDATE_TOOL_STATE',
        payload: { drawing: true, startPos: { x: modelPos.x, y: modelPos.y }, currentPos: { x: modelPos.x, y: modelPos.y } },
      });
    },

    onMouseMove(modelPos, e, toolState) {
      if (!toolState.drawing) return;
      editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { currentPos: { x: modelPos.x, y: modelPos.y } } });
    },

    onMouseUp(modelPos, e, toolState) {
      if (!toolState.drawing || !toolState.startPos) return;

      const svgX = Math.min(toolState.startPos.x, modelPos.x);
      const svgY = Math.min(toolState.startPos.y, modelPos.y);
      const svgW = Math.abs(modelPos.x - toolState.startPos.x);
      const svgH = Math.abs(modelPos.y - toolState.startPos.y);

      const minSize = 10;
      if (svgW > minSize && svgH > minSize) {
        const position = viewToModelPosition(svgX, svgY, activeView, { x: 0, y: 0, z: 0 });
        const extents = viewToModelExtents(svgW, svgH, activeView, { type: partType, ...defaults });

        const part = factory({
          position,
          ...extents,
          assemblyId: activeAssemblyId || null,
        });

        dispatch({ type: 'PART_ADD', part });

        if (activeAssemblyId) {
          dispatch({ type: 'ASSEMBLY_ADD_PART', assemblyId: activeAssemblyId, partId: part.id });
        }

        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: `${partType}: ${Math.round(svgW)} x ${Math.round(svgH)} mm` });
      }

      editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { drawing: false, startPos: null, currentPos: null } });
    },

    onKeyDown(e) {
      if (e.key === 'Escape') {
        editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { drawing: false, startPos: null, currentPos: null } });
      }
    },

    getCursor(toolState) { return 'crosshair'; },
  };
}
```

**`dimensionHandler.js`** -- Two-click handler for placing dimension annotations.

```javascript
export function createDimensionHandler({ dispatch, editorDispatch, activeView }) {
  return {
    onMouseDown(modelPos, e, toolState) {
      if (e.button !== 0) return;

      if (!toolState.firstPoint) {
        // First click: set start point
        editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { firstPoint: { x: modelPos.x, y: modelPos.y }, currentPos: modelPos } });
        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Click to set dimension end point' });
      } else {
        // Second click: create dimension
        const startPoint3D = viewToModelPosition(toolState.firstPoint.x, toolState.firstPoint.y, activeView, {x:0,y:0,z:0});
        const endPoint3D = viewToModelPosition(modelPos.x, modelPos.y, activeView, {x:0,y:0,z:0});

        const dim = createDimension({ startPoint: startPoint3D, endPoint: endPoint3D, offset: 200 });
        dispatch({ type: 'PART_ADD', part: dim });

        editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { firstPoint: null, currentPos: null } });
      }
    },
    onMouseMove(modelPos, e, toolState) {
      if (toolState.firstPoint) {
        editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { currentPos: modelPos } });
      }
    },
    onMouseUp() {},
    onKeyDown(e) {
      if (e.key === 'Escape') {
        editorDispatch({ type: 'UPDATE_TOOL_STATE', payload: { firstPoint: null, currentPos: null } });
      }
    },
    getCursor() { return 'crosshair'; },
  };
}
```

