import { sketchSerialize } from './sketchSerialize';
import { sketchDeserialize } from './sketchDeserialize';
import { localStorageBackend } from '@/persistence/localStorageBackend';

// Use a different prefix so sketch and floorplan projects don't collide
const SKETCH_INDEX_KEY = 'sketch-planner-projects';
const SKETCH_PREFIX = 'sketch-planner-project-';

// Create a sketch-specific backend that wraps localStorage with the sketch prefix
const sketchBackend = {
  async save(projectId, name, serialized) { ... },  // Same pattern, different keys
  async load(projectId) { ... },
  async list() { ... },
  async delete(projectId) { ... },
};

export async function saveSketchProject(project) {
  const serialized = sketchSerialize(project);
  await sketchBackend.save(project.id, project.name, serialized);
  return serialized.savedAt;
}

export async function loadSketchProject(projectId) {
  const json = await sketchBackend.load(projectId);
  if (!json) throw new Error('Sketch project not found');
  return sketchDeserialize(json);
}

export async function listSketchProjects() { return sketchBackend.list(); }
export async function deleteSketchProject(projectId) { await sketchBackend.delete(projectId); }
